  1→/**
  2→ * API Client Types
  3→ *
  4→ * Request and response types for Contact API client.
  5→ * Matches the API route contracts from /api/contacts and /api/contacts/[id].
  6→ */
  7→
  8→import type { Contact } from '@prisma/client';
  9→
 10→/**
 11→ * Base contact fields without Prisma metadata
 12→ */
 13→export type ContactData = Omit<
 14→  Contact,
 15→  'deletedAt'
 16→>;
 17→
 18→/**
 19→ * API error response shape
 20→ */
 21→export interface ApiError {
 22→  error: string;
 23→  message: string;
 24→}
 25→
 26→/**
 27→ * Success response wrapper with single item
 28→ */
 29→export interface ApiResponse<T> {
 30→  data: T;
 31→}
 32→
 33→/**
 34→ * Success response wrapper with array and count
 35→ */
 36→export interface ApiListResponse<T> {
 37→  data: T[];
 38→  count: number;
 39→}
 40→
 41→/**
 42→ * Contact filter options for getContacts
 43→ */
 44→export interface ContactFilters {
 45→  type?: 'person' | 'company';
 46→  status?: string;
 47→}
 48→
 49→/**
 50→ * Pagination options
 51→ */
 52→export interface PaginationOptions {
 53→  skip?: number;
 54→  take?: number;
 55→}
 56→
 57→/**
 58→ * Combined query parameters for listing contacts
 59→ */
 60→export interface ContactListParams extends ContactFilters, PaginationOptions {}
 61→
 62→/**
 63→ * Contact creation input
 64→ */
 65→export interface ContactCreateInput {
 66→  type: 'person' | 'company';
 67→  phone: string;
 68→  firstName?: string | null;
 69→  lastName?: string | null;
 70→  middleName?: string | null;
 71→  companyName?: string | null;
 72→  inn?: string | null;
 73→  kpp?: string | null;
 74→  ogrn?: string | null;
 75→  email?: string | null;
 76→  address?: string | null;
 77→  physicalAddress?: string | null;
 78→  position?: string | null;
 79→  notes?: string | null;
 80→  sourceId?: string | null;
 81→  ownerId?: string | null;
 82→  status?: string | null;
 83→  tags?: string[] | null;
 84→  attributes?: Record<string, unknown> | null;
 85→}
 86→
 87→/**
 88→ * Contact update input (all fields optional)
 89→ */
 90→export interface ContactUpdateInput {
 91→  type?: 'person' | 'company' | null;
 92→  firstName?: string | null;
 93→  lastName?: string | null;
 94→  middleName?: string | null;
