230→      const invalidData: ContactCreateInput = {
231→        type: 'person',
232→        phone: '+1234567890',
233→      };
234→
235→      const mockError = {
236→        error: 'Validation failed',
237→        message: 'firstName is required for person contacts',
238→      };
239→
240→      client.fetchFn = createMockFetch(mockError, 400, false);
241→
242→      await assert.rejects(
243→        async () => client.createContact(invalidData),
244→        (err: unknown) => {
245→          assert.ok(err instanceof ApiClientError);
