251→
252→    it('should handle validation error (missing companyName for company)', async () => {
253→      const invalidData: ContactCreateInput = {
254→        type: 'company',
255→        phone: '+1234567890',
256→      };
257→
258→      const mockError = {
259→        error: 'Validation failed',
260→        message: 'companyName is required for company contacts',
261→      };
262→
263→      client.fetchFn = createMockFetch(mockError, 400, false);
264→
265→      await assert.rejects(
266→        async () => client.createContact(invalidData),
267→        (err: unknown) => {
268→          assert.ok(err instanceof ApiClientError);
