299→    it('should send POST request', async () => {
300→      const createData: ContactCreateInput = {
301→        type: 'person',
302→        firstName: 'Test',
303→        phone: '+1234567890',
304→      };
305→
306→      let capturedOptions: RequestInit | undefined;
307→
308→      client.fetchFn = async (_url, options) => {
309→        capturedOptions = options;
310→        return {
311→          ok: true,
312→          status: 201,
313→          json: async () => ({ data: mockContact }),
314→          headers: { get: () => 'application/json' },
