317→
318→      await client.createContact(createData);
319→
320→      assert.strictEqual(capturedOptions?.method, 'POST');
321→    });
322→  });
323→
324→  describe('updateContact', () => {
325→    it('should update contact and return updated data', async () => {
326→      const updateData: ContactUpdateInput = {
327→        firstName: 'Updated',
328→        notes: 'Updated notes',
329→      };
330→
331→      const mockResponse = {
332→        data: { ...mockContact, ...updateData },
333→      };
334→
335→      client.fetchFn = createMockFetch(mockResponse);
