371→
372→    it('should send PUT request', async () => {
373→      let capturedOptions: RequestInit | undefined;
374→
375→      client.fetchFn = async (_url, options) => {
376→        capturedOptions = options;
377→        return {
378→          ok: true,
379→          status: 200,
380→          json: async () => ({ data: mockContact }),
381→          headers: { get: () => 'application/json' },
382→        } as Response;
383→      };
384→
385→      await client.updateContact(mockContact.id, { firstName: 'Test' });
386→
387→      assert.strictEqual(capturedOptions?.method, 'PUT');
388→    });
